/* Bay Sentinel v9.0 — Full Upgrade: CSV Upload, Review, Advanced Search, Active Op Details */
(function(){
"use strict";
const LOGO=(window.__STATIC||'/static/')+'images/logo_00.png';
const S={user:null,token:null,refresh:null,view:"login",leads:[],lead:null,stats:{},mapData:[],scrapers:[],scraperSum:{},operations:{},opHistory:[],activeOps:[],devData:null,config:{},filters:{},page:1,pages:1,count:0,exportPreview:null,activeOpsTimer:null,scraperTab:"operations",selectedLeads:new Set(),ws:null,wsReconnect:null,lastEventTs:0,pollTimer:null,searchConfig:null,advSearchOpen:false,importBatches:[],currentBatch:null,mapMarkers:[],mapInstance:null,mapClusterer:null,mapInfoWindow:null};

const API={
base:"/api/v1",
async req(ep,opts={}){
const url=ep.startsWith("http")?ep:this.base+ep;
const h={...opts.headers};
if(!(opts.body instanceof FormData))h["Content-Type"]="application/json";
if(S.token)h.Authorization="Bearer "+S.token;
try{const r=await fetch(url,{...opts,headers:h});
if(r.status===401&&S.refresh){if(await this.doRefresh()){h.Authorization="Bearer "+S.token;const r2=await fetch(url,{...opts,headers:h});if(!r2.ok)throw new Error("HTTP "+r2.status);return r2.json();}S.token=null;S.refresh=null;S.user=null;localStorage.clear();nav("login");return null;}
if(!r.ok){const e=await r.json().catch(()=>({}));throw new Error(e.error||e.detail||"HTTP "+r.status);}
return r.json();}catch(e){console.error("API:",e);throw e;}},
async doRefresh(){try{const r=await fetch(this.base+"/auth/refresh/",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({refresh:S.refresh})});if(!r.ok)return false;const d=await r.json();S.token=d.access;if(d.refresh)S.refresh=d.refresh;localStorage.setItem("token",S.token);if(d.refresh)localStorage.setItem("refresh",d.refresh);return true;}catch{return false;}},
get(e){return this.req(e)},post(e,b){return this.req(e,{method:"POST",body:JSON.stringify(b)})},
upload(e,formData){return this.req(e,{method:"POST",body:formData})},
del(e){return this.req(e,{method:"DELETE"})}
};

const routes={};function reg(p,h){routes[p]=h}
function nav(p,params={}){S.view=p;const url=p==="login"?"/login":p==="lead"?"/lead/"+(params.id||0):"/"+p;window.history.pushState({p,params},"",url);localStorage.setItem("lastView",JSON.stringify({p,params}));if(S.activeOpsTimer){clearInterval(S.activeOpsTimer);S.activeOpsTimer=null;}if(S.mapMarkers.length){S.mapMarkers.forEach(function(m){m.setMap(null)});S.mapMarkers=[];}if(S.mapClusterer){S.mapClusterer.clearMarkers();S.mapClusterer=null;}if(S.mapInfoWindow){S.mapInfoWindow.close();S.mapInfoWindow=null;}S.mapInstance=null;(routes[p]||routes.login)(params);}
window.addEventListener("popstate",e=>{const s=e.state||{p:"login"};(routes[s.p]||routes.login)(s.params||{});});

let toastBox;function toast(msg,type){type=type||"info";if(!toastBox){toastBox=document.createElement("div");toastBox.className="toast-box";document.body.appendChild(toastBox);}const ic={ok:"fa-check-circle",err:"fa-exclamation-circle",info:"fa-info-circle"};const cl={ok:"emerald",err:"red",info:"blue"};const t=document.createElement("div");t.className="toast "+type;t.innerHTML='<i class="fas '+(ic[type]||ic.info)+'" style="color:var(--'+(cl[type]||cl.info)+')"></i><span class="toast-msg">'+msg+'</span><span class="toast-x" onclick="this.parentElement.remove()">&times;</span>';toastBox.appendChild(t);setTimeout(()=>{if(t.parentElement)t.remove()},7000);}

const $=(s,c)=>(c||document).querySelector(s);
const $$=(s,c)=>[...(c||document).querySelectorAll(s)];
const app=document.getElementById("app");
function money(v){if(!v)return"\u2014";const n=parseFloat(v);if(n>=1e6)return"$"+(n/1e6).toFixed(1)+"M";if(n>=1e3)return"$"+(n/1e3).toFixed(0)+"K";return"$"+n.toLocaleString();}
function fdate(d){return d?new Date(d).toLocaleDateString():"\u2014";}
function ftime(d){return d?new Date(d).toLocaleString():"\u2014";}
function sc(s){return s>=80?"score-hot":s>=50?"score-warm":"score-cold";}
function pc(p){return"pri-"+p;}
function initials(n){return n?n.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase():"?";}
function fq(){return Object.entries(S.filters).filter(([,v])=>v!==undefined&&v!=="").map(([k,v])=>k+"="+encodeURIComponent(v)).join("&");}
function stColor(s){return s==="completed"?"var(--emerald)":s==="failed"?"var(--red)":s==="partial"?"var(--amber)":s==="running"?"var(--blue)":"var(--text-500)";}
function stIcon(s){return s==="completed"?"fa-check-circle":s==="failed"?"fa-times-circle":s==="partial"?"fa-exclamation-circle":s==="running"?"fa-spinner fa-spin":s==="cancelled"?"fa-stop-circle":"fa-clock";}
function loading(h){setTimeout(function(){var w=document.querySelector("[data-loading-wrap]");if(w&&!w.querySelector(".retry-btn")){var rb=document.createElement("button");rb.className="btn btn-secondary btn-sm retry-btn";rb.style.marginTop="8px";rb.textContent="Retry";rb.onclick=function(){nav(S.view)};w.appendChild(rb);}},15000);return'<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:'+(h||"60vh")+';gap:12px" data-loading-wrap="1"><div class="spinner" style="width:40px;height:40px;border-width:3px"></div><div style="color:var(--text-500);font-size:12px">Loading data...</div></div>';}
function particles(el,n){const c=["","particle-blue","particle-purple","particle-cyan"];for(let i=0;i<(n||20);i++){const p=document.createElement("div");p.className="particle "+c[Math.floor(Math.random()*c.length)];const s=Math.random()*2.5+.5;p.style.cssText="left:"+Math.random()*100+"%;top:"+Math.random()*100+"%;width:"+s+"px;height:"+s+"px;animation-duration:"+(Math.random()*25+15)+"s;animation-delay:"+(Math.random()*15)+"s;";el.appendChild(p);}}
function parallaxBg(){return'<div class="parallax-scene"><div class="parallax-layer parallax-gradient"></div><div class="parallax-layer parallax-nebula"></div><div class="parallax-layer parallax-grid"></div><div class="parallax-orb orb-1"></div><div class="parallax-orb orb-2"></div><div class="parallax-orb orb-3"></div><div class="parallax-layer" id="particleLayer"></div></div>';}
function logoImg(sz){return'<img src="'+LOGO+'" alt="" style="width:'+(sz||"100%")+';height:'+(sz||"100%")+';object-fit:cover" onerror="this.outerHTML=\'<span style=font-size:24px>BS</span>\'">';}

/* WS + Polling */
function connectWS(){if(S.ws)try{S.ws.close()}catch(e){}try{const proto=location.protocol==="https:"?"wss:":"ws:";S.ws=new WebSocket(proto+"//"+location.host+"/ws/operations/");S.ws.onopen=function(){if(S.wsReconnect){clearTimeout(S.wsReconnect);S.wsReconnect=null;}if(S.pollTimer){clearInterval(S.pollTimer);S.pollTimer=null;}};S.ws.onmessage=function(e){handleRealtimeEvent(JSON.parse(e.data));};S.ws.onclose=function(){S.wsReconnect=setTimeout(()=>{connectWS()},4000);startPolling();};S.ws.onerror=function(){startPolling();};}catch(e){startPolling();}}
function startPolling(){if(S.pollTimer)return;S.pollTimer=setInterval(async()=>{try{const events=await API.get("/notifications/events/?since="+S.lastEventTs);if(events&&events.length)events.forEach(e=>{S.lastEventTs=Math.max(S.lastEventTs,e.ts||0);handleRealtimeEvent(e.data);});}catch(e){}},3000);}
function handleRealtimeEvent(d){if(!d||!d.type)return;if(d.type==="op_update"){if(S.view==="scrapers"&&S.scraperTab==="active")updateActiveOpInPlace(d);if(d.completed){toast(d.label+": "+(d.status||"done"),d.status==="completed"?"ok":"err");if(S.view==="scrapers")setTimeout(()=>refreshActiveTab(),500);}}if(d.type==="notification"){toast(d.title+(d.message?" \u2014 "+d.message:""),d.level==="success"?"ok":d.level==="error"?"err":"info");}}
function updateActiveOpInPlace(d){const el=document.getElementById("active-op-"+d.op_id);if(!el)return;const stepEl=el.querySelector(".op-live-step");if(stepEl)stepEl.textContent=d.step||"";const progEl=el.querySelector(".progress-fill");if(progEl)progEl.style.width=(d.progress||0)+"%";const crEl=el.querySelector(".op-cr");if(crEl&&d.leads_created!==undefined)crEl.textContent="+"+d.leads_created+" new";const upEl=el.querySelector(".op-up");if(upEl&&d.leads_updated!==undefined)upEl.textContent=d.leads_updated+" upd";const enEl=el.querySelector(".op-en");if(enEl&&d.leads_enriched!==undefined)enEl.textContent=d.leads_enriched+" enr";const faEl=el.querySelector(".op-fa");if(faEl&&d.leads_failed!==undefined)faEl.textContent=d.leads_failed+" fail";}
async function refreshActiveTab(){try{S.activeOps=await API.get("/enrichment/active/");if(S.view==="scrapers"&&S.scraperTab==="active")renderActiveTab($("#scraperContent"));}catch(e){}}

/* Login */
reg("login",()=>{
app.innerHTML=parallaxBg()+'<div class="login-wrap"><div class="login-card"><div class="login-brand"><div class="login-logo">'+logoImg()+'</div><h1>Bay Sentinel</h1><p>Amazing Ventures LLC</p></div><div id="loginErr"></div><form id="loginForm"><div class="form-group"><label class="form-label">Username</label><input type="text" class="form-input" id="lu" placeholder="Enter username" required></div><div class="form-group"><label class="form-label">Password</label><input type="password" class="form-input" id="lp" placeholder="Enter password" required></div><button type="submit" class="btn btn-primary" id="lBtn" style="width:100%"><i class="fas fa-sign-in-alt"></i> Sign In</button></form><div style="text-align:center;margin-top:28px;padding-top:20px;border-top:1px solid var(--border)"><span style="font-size:11px;color:var(--text-500);letter-spacing:.5px">Built by <a href="https://nextautomation.us" target="_blank" style="color:var(--blue);font-weight:600">NextAutomation</a></span></div></div></div>';
const pl=$("#particleLayer");if(pl)particles(pl,30);
$("#loginForm").onsubmit=async e=>{e.preventDefault();const btn=$("#lBtn");btn.innerHTML='<div class="spinner" style="width:16px;height:16px;border-width:2px"></div>';btn.disabled=true;try{const d=await API.post("/auth/login/",{username:$("#lu").value,password:$("#lp").value});S.token=d.access;S.refresh=d.refresh;S.user=d.user;localStorage.setItem("token",d.access);localStorage.setItem("refresh",d.refresh);localStorage.setItem("user",JSON.stringify(d.user));connectWS();intro();}catch(err){$("#loginErr").innerHTML='<div class="login-error"><i class="fas fa-exclamation-triangle"></i>'+err.message+'</div>';btn.innerHTML='<i class="fas fa-sign-in-alt"></i> Sign In';btn.disabled=false;}};
});

function intro(){app.innerHTML=parallaxBg()+'<div class="intro" id="introEl"><div class="intro-logo">'+logoImg()+'</div><h1>Bay Sentinel</h1><div class="intro-sub">Welcome back, '+(S.user.first_name||S.user.username)+'</div><div class="intro-bar"><div class="intro-bar-fill" id="iBar"></div></div><div class="intro-status" id="iStatus">Initializing...</div></div>';const pl=$("#particleLayer");if(pl)particles(pl,35);const steps=[[15,"Connecting..."],[35,"Loading data..."],[55,"Syncing sources..."],[78,"Computing scores..."],[95,"Rendering..."],[100,"Ready."]];let i=0;const iv=setInterval(()=>{if(i>=steps.length){clearInterval(iv);const el=$("#introEl");if(el)el.classList.add("exit");setTimeout(()=>nav("dashboard"),800);return;}const b=$("#iBar"),st=$("#iStatus");if(b)b.style.width=steps[i][0]+"%";if(st)st.textContent=steps[i][1];i++;},320);}

function shell(active,content){
const adm=S.user&&(S.user.is_admin_role||S.user.role==="admin");
const sidebarCollapsed=localStorage.getItem("sb_collapsed")==="1";app.innerHTML=parallaxBg()+'<div class="hamburger" id="hamBtn"><i class="fas fa-bars"></i></div><div class="layout'+(sidebarCollapsed?" collapsed":"")+'"><nav class="sidebar'+(sidebarCollapsed?" collapsed":"")+'" id="sidebar"><div class="sb-brand"><div class="sb-brand-row"><div class="sb-logo">'+logoImg()+'</div><div><h2>Bay Sentinel</h2><span>AMAZING VENTURES LLC</span></div><button class="sb-collapse-btn" id="collapseBtn" title="Toggle sidebar"><i class="fas fa-chevron-left"></i></button></div></div><div class="sb-nav"><div class="sb-section"><div class="sb-section-label">Intelligence</div><div class="nav-item '+(active==="dashboard"?"active":"")+'" data-n="dashboard"><i class="fas fa-chart-line"></i>Dashboard</div><div class="nav-item '+(active==="map"?"active":"")+'" data-n="map"><i class="fas fa-map-marked-alt"></i>Map View</div><div class="nav-item '+(active==="export"?"active":"")+'" data-n="export"><i class="fas fa-file-export"></i>Export Center</div><div class="nav-item '+(active==="import"?"active":"")+'" data-n="import"><i class="fas fa-file-import"></i>Import CSV</div></div>'+(adm?'<div class="sb-section"><div class="sb-section-label">Command</div><div class="nav-item '+(active==="scrapers"?"active":"")+'" data-n="scrapers"><i class="fas fa-bolt"></i>Triggers'+(S.activeOps.length?'<span class="nav-badge warn">'+S.activeOps.length+'</span>':'')+'</div></div>':'')+'</div><div style="padding:12px 20px;text-align:center"><a href="https://nextautomation.us" target="_blank" style="font-size:10px;color:var(--text-500);letter-spacing:.3px;text-decoration:none">Built by <span style="color:var(--blue);font-weight:600">NextAutomation</span></a></div><div class="sb-user"><div class="avatar">'+initials(S.user?.first_name||S.user?.username)+'</div><div class="sb-user-info"><div class="name">'+(S.user?.first_name||S.user?.username||"User")+'</div><div class="role">'+(S.user?.role||"viewer")+'</div></div><i class="fas fa-sign-out-alt" style="cursor:pointer;color:var(--text-500)" id="logoutBtn"></i></div></nav><main class="main" id="mc">'+content+'</main></div>';
const pl=$("#particleLayer");if(pl)particles(pl,12);
$$(".nav-item[data-n]").forEach(el=>{el.onclick=()=>{nav(el.dataset.n);$("#sidebar")?.classList.remove("open");}});
const lo=$("#logoutBtn");if(lo)lo.onclick=()=>{localStorage.clear();S.token=null;S.user=null;nav("login");};
const ham=$("#hamBtn");if(ham)ham.onclick=()=>{$("#sidebar")?.classList.toggle("open");};
const colBtn=$("#collapseBtn");if(colBtn)colBtn.onclick=()=>{const sb=$("#sidebar");const ly=sb?.closest(".layout");if(sb){sb.classList.toggle("collapsed");ly?.classList.toggle("collapsed");localStorage.setItem("sb_collapsed",sb.classList.contains("collapsed")?"1":"0");}if(S.mapInstance){setTimeout(()=>{google.maps.event.trigger(S.mapInstance,"resize")},350);}};
}

/* Dashboard */
reg("dashboard",async()=>{
shell("dashboard",loading());
try{const[stats,lr,cfg]=await Promise.all([API.get("/leads/stats/?"+fq()),API.get("/leads/?ordering=-distress_score&page="+S.page+"&"+fq()),API.get("/leads/config/")]);S.stats=stats;S.leads=lr.results||[];S.count=lr.count||0;S.pages=Math.ceil(S.count/50);S.config=cfg;}catch(e){toast("Failed to load","err");}
const mc=$("#mc"),st=S.stats;if(!mc)return;S.selectedLeads.clear();
mc.innerHTML='<div class="page-head anim-down"><div><h1>Dashboard</h1><div class="sub">'+(S.count||0).toLocaleString()+' distressed properties across the Bay Area</div></div><div class="page-actions"><button class="btn btn-secondary btn-sm" id="advSearchBtn"><i class="fas fa-search-plus"></i> Advanced Search</button><button class="btn btn-secondary btn-sm" onclick="nav(\'export\')"><i class="fas fa-download"></i> Export</button></div></div>'+
'<div class="stats-row"><div class="stat blue anim-up d1"><div class="stat-icon ic-blue"><i class="fas fa-building"></i></div><div class="stat-val">'+(st.total||0).toLocaleString()+'</div><div class="stat-label">Total Leads</div></div><div class="stat hot anim-up d2"><div class="stat-icon ic-red"><i class="fas fa-fire"></i></div><div class="stat-val">'+(st.hot_count||0).toLocaleString()+'</div><div class="stat-label">Critical (80+)</div></div><div class="stat warm anim-up d3"><div class="stat-icon ic-amber"><i class="fas fa-bolt"></i></div><div class="stat-val">'+(st.warm_count||0).toLocaleString()+'</div><div class="stat-label">High Priority</div></div><div class="stat emerald anim-up d4"><div class="stat-icon ic-emerald"><i class="fas fa-signal"></i></div><div class="stat-val">'+(st.with_signals||0).toLocaleString()+'</div><div class="stat-label">Active Signals</div></div><div class="stat purple anim-up d5"><div class="stat-icon ic-purple"><i class="fas fa-chart-pie"></i></div><div class="stat-val">'+Math.round((st.avg_completeness||0)*100)+'%</div><div class="stat-label">Data Complete</div></div></div>'+
'<div id="advSearchPanel" style="display:none"></div>'+
'<div id="activeFiltersBar" class="active-filters-bar"></div>'+
'<div id="chartsArea" class="charts-grid"></div>'+
'<div class="filters anim-up d3"><div class="f-group"><span class="f-label">County</span><select class="f-select" id="fCo"><option value="">All Counties</option>'+["Santa Clara","San Mateo","Alameda","San Francisco","Contra Costa","Marin","Sonoma","Napa","Solano"].map(c=>'<option '+(S.filters.county===c?"selected":"")+'>'+c+'</option>').join("")+'</select></div><div class="f-group"><span class="f-label">Signal</span><select class="f-select" id="fSig"><option value="">All</option><option value="nod">NOD</option><option value="auction">Auction</option><option value="tax_delinquent">Tax Delinq</option><option value="vacancy">Vacancy</option><option value="absentee">Absentee</option></select></div><div class="f-group"><span class="f-label">Priority</span><select class="f-select" id="fPri"><option value="">All</option><option value="critical">Critical</option><option value="high">High</option><option value="med">Medium</option><option value="low">Low</option></select></div><div class="f-group"><span class="f-label">Min Score</span><input type="number" class="f-input" id="fScore" min="0" max="100" value="'+(S.filters.min_distress||"")+'" style="width:65px" placeholder="0"></div><div style="margin-left:auto"><button class="btn btn-primary btn-sm" id="applyF"><i class="fas fa-filter"></i> Apply</button> <button class="btn btn-ghost btn-sm" id="clearF"><i class="fas fa-times"></i></button></div></div>'+
'<div class="bulk-bar" id="bulkBar"><span class="bulk-count" id="bulkCount">0</span> selected<button class="btn btn-secondary btn-xs" onclick="window.__bulk(\'enrich\')"><i class="fas fa-magic"></i> Enrich</button><button class="btn btn-secondary btn-xs" onclick="window.__bulk(\'export\')"><i class="fas fa-download"></i> Export</button><button class="btn btn-ghost btn-xs" onclick="S.selectedLeads.clear();updateBulk();renderTable()">Clear</button></div>'+
'<div class="table-wrap anim-up d4"><div class="table-inner" id="tbl"></div></div><div class="pager" id="pgr"></div>';
renderTable();renderPager();renderActiveFilters();loadCharts();
$("#applyF").onclick=()=>{S.filters={...S.filters,county:$("#fCo").value,signal_type:$("#fSig").value,priority:$("#fPri").value,min_distress:$("#fScore").value};S.page=1;nav("dashboard");};
$("#clearF").onclick=()=>{S.filters={};S.page=1;nav("dashboard");};
$("#advSearchBtn").onclick=()=>openAdvancedSearch();
});

function renderActiveFilters(){const bar=$("#activeFiltersBar");if(!bar)return;const active=Object.entries(S.filters).filter(([,v])=>v!==undefined&&v!=="");if(!active.length){bar.innerHTML="";return;}bar.innerHTML=active.map(([k,v])=>'<span class="af-chip">'+k.replace(/_/g," ")+': '+v+' <span class="af-x" data-k="'+k+'">&times;</span></span>').join("")+'<span class="af-chip" style="cursor:pointer;background:rgba(239,68,68,0.08);color:var(--red)" onclick="S.filters={};nav(\'dashboard\')">Clear all</span>';$$(".af-x",bar).forEach(x=>{x.onclick=e=>{e.stopPropagation();delete S.filters[x.dataset.k];nav("dashboard");}});}

async function openAdvancedSearch(){
if(!S.searchConfig){try{S.searchConfig=await API.get("/leads/search_config/");}catch(e){toast("Failed to load search config","err");return;}}
const sc=S.searchConfig,panel=$("#advSearchPanel");if(!panel)return;
if(panel.style.display!=="none"){panel.style.display="none";return;}
const sections=sc.filters;let h='<div class="adv-search-panel anim-up">';
const sectionLabels={location:"\ud83d\udccd Location",scores:"\ud83c\udfaf Scores & Priority",financial:"\ud83d\udcb0 Financial",property:"\ud83c\udfe0 Property",owner:"\ud83d\udc64 Owner",signals:"\u26a0\ufe0f Distress Signals",hazard:"\ud83d\udd25 Hazard & Opportunity",quality:"\ud83d\udcca Data Quality",dates:"\ud83d\udcc5 Dates"};
for(const[sKey,filters]of Object.entries(sections)){
h+='<div class="as-section"><div class="as-section-title">'+(sectionLabels[sKey]||sKey)+'</div><div class="as-grid">';
for(const f of filters){
const cv=S.filters[f.key]||"";
if(f.type==="select"){
let opts='<option value="">Any</option>';
if(f.options){opts+=f.options.map(o=>'<option value="'+o+'" '+(cv===o?"selected":"")+'>'+o+'</option>').join("");}
else if(f.key==="county"){opts+=sc.counties.map(o=>'<option value="'+o+'" '+(cv===o?"selected":"")+'>'+o+'</option>').join("");}
else if(f.key==="property_type"){opts+=sc.property_types.map(o=>'<option value="'+o+'" '+(cv===o?"selected":"")+'>'+o+'</option>').join("");}
else if(f.key==="wildfire_risk"){opts+=sc.wildfire_options.map(o=>'<option value="'+o+'" '+(cv===o?"selected":"")+'>'+o+'</option>').join("");}
else if(f.key==="flood_zone"){opts+=sc.flood_options.map(o=>'<option value="'+o+'" '+(cv===o?"selected":"")+'>'+o+'</option>').join("");}
else if(f.key==="priority"){opts+=sc.priorities.map(o=>'<option value="'+o.value+'" '+(cv===o.value?"selected":"")+'>'+o.label+'</option>').join("");}
else if(f.key==="status"){opts+=sc.statuses.map(o=>'<option value="'+o.value+'" '+(cv===o.value?"selected":"")+'>'+o.label+'</option>').join("");}
h+='<div class="as-field"><label>'+f.label+'</label><select data-key="'+f.key+'">'+opts+'</select></div>';
}else if(f.type==="bool"){
h+='<div class="as-toggle"><input type="checkbox" id="as_'+f.key+'" data-key="'+f.key+'" '+(cv==="true"?"checked":"")+'><label for="as_'+f.key+'">'+f.label+'</label></div>';
}else if(f.type==="date"){
h+='<div class="as-field"><label>'+f.label+'</label><input type="date" data-key="'+f.key+'" value="'+(cv||"")+'"></div>';
}else{
h+='<div class="as-field"><label>'+f.label+'</label><input type="'+(f.type||"text")+'" data-key="'+f.key+'" value="'+(cv||"")+'" '+(f.min!==undefined?'min="'+f.min+'"':'')+' '+(f.max!==undefined?'max="'+f.max+'"':'')+' placeholder="'+f.label+'"></div>';
}
}
h+='</div></div>';}
h+='<div class="as-actions"><button class="btn btn-ghost btn-sm" id="asClear">Clear All</button><button class="btn btn-primary btn-sm" id="asApply"><i class="fas fa-search"></i> Search</button></div></div>';
panel.innerHTML=h;panel.style.display="block";
$("#asApply").onclick=()=>{const newF={};$$("[data-key]",panel).forEach(el=>{const k=el.dataset.key;if(el.type==="checkbox"){if(el.checked)newF[k]="true";}else{if(el.value)newF[k]=el.value;}});S.filters=newF;S.page=1;panel.style.display="none";nav("dashboard");};
$("#asClear").onclick=()=>{S.filters={};S.page=1;panel.style.display="none";nav("dashboard");};
}

function renderTable(){const t=$("#tbl");if(!t)return;t.innerHTML='<table><thead><tr><th class="cb-cell"><input type="checkbox" id="selectAll"></th><th>Score</th><th>Address</th><th>County</th><th>Value</th><th>Signals</th><th>Owner</th><th>Priority</th></tr></thead><tbody>'+S.leads.map(l=>'<tr class="'+(S.selectedLeads.has(l.id)?"selected":"")+'" data-id="'+l.id+'"><td class="cb-cell"><input type="checkbox" class="lcb" data-id="'+l.id+'" '+(S.selectedLeads.has(l.id)?"checked":"")+'></td><td><span class="score '+sc(l.distress_score)+'">'+l.distress_score+'</span></td><td style="font-weight:600;max-width:200px;overflow:hidden;text-overflow:ellipsis">'+l.address+'</td><td>'+l.county+'</td><td style="font-family:var(--mono);font-size:12px">'+money(l.estimated_value||l.assessed_value)+'</td><td>'+(l.active_signals||[]).slice(0,2).map(s=>'<span class="pill">'+s.name.split(" ").slice(0,2).join(" ")+'</span>').join("")+'</td><td style="max-width:120px;overflow:hidden;text-overflow:ellipsis">'+(l.owner_name||"\u2014")+'</td><td><span class="pri '+pc(l.lead_priority)+'">'+l.lead_priority+'</span></td></tr>').join("")||'<tr><td colspan="8" style="text-align:center;padding:40px;color:var(--text-500)">No leads found</td></tr>'+'</tbody></table>';
$$("tr[data-id]",t).forEach(tr=>{tr.onclick=e=>{if(e.target.type==="checkbox")return;nav("lead",{id:parseInt(tr.dataset.id)});};});
$$(".lcb",t).forEach(cb=>{cb.onclick=e=>{e.stopPropagation();const id=parseInt(cb.dataset.id);if(cb.checked)S.selectedLeads.add(id);else S.selectedLeads.delete(id);updateBulk();};});
const sa=$("#selectAll");if(sa)sa.onclick=()=>{if(sa.checked)S.leads.forEach(l=>S.selectedLeads.add(l.id));else S.leads.forEach(l=>S.selectedLeads.delete(l.id));renderTable();updateBulk();};}
function updateBulk(){const bar=$("#bulkBar"),cnt=$("#bulkCount");if(bar)bar.classList.toggle("visible",S.selectedLeads.size>0);if(cnt)cnt.textContent=S.selectedLeads.size;}
window.__bulk=async(action)=>{if(!S.selectedLeads.size)return;try{const r=await API.post("/leads/bulk_action/",{action,lead_ids:[...S.selectedLeads]});toast(r.message,"ok");S.selectedLeads.clear();updateBulk();}catch(e){toast(e.message,"err");}};
function renderPager(){const c=$("#pgr");if(!c||S.pages<=1){if(c)c.innerHTML="";return;}let h='<button '+(S.page<=1?"disabled":"")+" onclick=\"S.page="+(S.page-1)+";nav('dashboard')\">\u00ab</button>";for(let i=Math.max(1,S.page-3);i<=Math.min(S.pages,S.page+3);i++)h+='<button class="'+(i===S.page?"cur":"")+'" onclick="S.page='+i+";nav('dashboard')\">"+i+"</button>";h+='<button '+(S.page>=S.pages?"disabled":"")+" onclick=\"S.page="+(S.page+1)+";nav('dashboard')\">\u00bb</button>";c.innerHTML=h;}
async function loadCharts(){const area=$("#chartsArea");if(!area)return;try{const[dist,trend]=await Promise.all([API.get("/dashboard/charts/distress/"),API.get("/dashboard/charts/leads-trend/")]);area.innerHTML='<div class="chart-card anim-up d4"><div class="card-header"><h3><i class="fas fa-chart-bar" style="color:var(--blue-bright)"></i> Score Distribution</h3></div><canvas id="ch1" height="200"></canvas></div><div class="chart-card anim-up d5"><div class="card-header"><h3><i class="fas fa-chart-area" style="color:var(--emerald)"></i> New Leads (30d)</h3></div><canvas id="ch2" height="200"></canvas></div>';if(window.Chart){Chart.defaults.color="#94a3b8";Chart.defaults.borderColor="rgba(0,0,0,0.06)";new Chart(document.getElementById("ch1"),{type:"bar",data:{labels:dist.labels,datasets:[{data:dist.values,backgroundColor:dist.labels.map(l=>{const v=parseInt(l);return v>=80?"rgba(220,38,38,0.6)":v>=50?"rgba(217,119,6,0.5)":"rgba(100,116,139,0.15)";}),borderRadius:8,borderSkipped:false}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false}},y:{grid:{color:"rgba(0,0,0,0.04)"}}}}});new Chart(document.getElementById("ch2"),{type:"line",data:{labels:trend.map(t=>t.date.slice(5)),datasets:[{data:trend.map(t=>t.count),borderColor:"#3b82f6",backgroundColor:"rgba(0,73,184,0.06)",fill:true,tension:.45,pointRadius:1.5,borderWidth:2}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{grid:{display:false},ticks:{maxTicksLimit:10}},y:{grid:{color:"rgba(0,0,0,0.04)"}}}}});}}catch(e){area.innerHTML="";}}

/* Lead Detail */
reg("lead",async params=>{
shell("dashboard",loading());try{const[ld,cfg]=await Promise.all([API.get("/leads/"+params.id+"/"),S.config.google_maps_key?Promise.resolve(S.config):API.get("/leads/config/")]);S.lead=ld;S.config=cfg;}catch(e){toast("Failed","err");return;}
const l=S.lead,mc=$("#mc");if(!mc)return;
const gk=S.config.google_maps_key||"";
const fullAddr=encodeURIComponent((l.address||"")+(l.city?", "+l.city:", ")+"CA "+(l.zip_code||""));const mapUrl=gk?"https://www.google.com/maps/embed/v1/place?key="+gk+"&q="+fullAddr+"&zoom=17":"https://maps.google.com/maps?q="+fullAddr+"&output=embed";
mc.innerHTML='<div class="page-head anim-down"><div style="display:flex;align-items:center;gap:14px"><button class="btn btn-ghost btn-icon" onclick="nav(\'dashboard\')"><i class="fas fa-arrow-left"></i></button><div><h1>'+(l.address||"Unknown Address")+'</h1><div class="sub">'+(l.city||l.county)+', CA '+(l.zip_code||"")+' \u2022 APN: <span style="font-family:var(--mono)">'+l.apn+'</span></div></div></div><div class="page-actions"><span class="score '+sc(l.distress_score)+'" style="font-size:24px;padding:12px 22px">'+l.distress_score+'</span></div></div><div class="tabs" id="dtabs"><button class="tab-btn active" data-t="overview"><i class="fas fa-eye"></i> Overview</button><button class="tab-btn" data-t="property"><i class="fas fa-home"></i> Property</button><button class="tab-btn" data-t="owner"><i class="fas fa-user"></i> Owner</button><button class="tab-btn" data-t="history"><i class="fas fa-clock"></i> History</button><button class="tab-btn" data-t="comps"><i class="fas fa-balance-scale"></i> Comps</button></div><div id="dtab"></div>';
$$("#dtabs .tab-btn").forEach(b=>{b.onclick=()=>{$$("#dtabs .tab-btn").forEach(x=>x.classList.remove("active"));b.classList.add("active");renderDTab(b.dataset.t);}});renderDTab("overview");
function renderDTab(tab){const dc=$("#dtab");if(!dc)return;if(tab==="overview"){dc.innerHTML='<div class="detail-hero anim-up d1"><div class="map-embed"><iframe src="'+mapUrl+'" allowfullscreen loading="lazy"></iframe></div><div class="card"><h3 style="font-size:14px;font-weight:700;margin-bottom:16px"><i class="fas fa-bolt" style="color:var(--amber)"></i> Distress Signals</h3><div class="signals-wrap">'+(l.active_signals||[]).map(s=>'<div class="signal-tag"><i class="fas fa-exclamation-triangle"></i>'+s.name+'<span class="w">+'+s.weight+'</span></div>').join("")||'<span style="color:var(--text-500)">No active signals</span>'+'</div></div></div><div class="stats-row anim-up d2"><div class="stat blue"><div class="stat-val">'+l.distress_score+'</div><div class="stat-label">Distress</div></div><div class="stat emerald"><div class="stat-val">'+l.upside_score+'</div><div class="stat-label">Upside</div></div><div class="stat purple"><div class="stat-val">'+Math.round((l.completeness||0)*100)+'%</div><div class="stat-label">Complete</div></div><div class="stat cyan"><div class="stat-val">'+money(l.estimated_value||l.assessed_value)+'</div><div class="stat-label">Value</div></div></div>';}else if(tab==="property"){dc.innerHTML='<div class="card anim-up">'+[["Type",l.property_type],["Beds",l.beds],["Baths",l.baths],["Living SqFt",l.sqft_living?l.sqft_living.toLocaleString():"\u2014"],["Lot SqFt",l.sqft_lot?l.sqft_lot.toLocaleString():"\u2014"],["Year Built",l.year_built],["Zoning",l.zoning],["Assessed",money(l.assessed_value)],["Estimated",money(l.estimated_value)],["Last Sale",fdate(l.last_sale_date)],["Sale Price",money(l.last_sale_price)],["Wildfire",l.wildfire_risk||"\u2014"],["Flood Zone",l.flood_zone||"\u2014"]].map(([k,v])=>'<div class="d-row"><span class="d-label">'+k+'</span><span class="d-val">'+(v||"\u2014")+'</span></div>').join("")+'</div>';}else if(tab==="owner"){dc.innerHTML='<div class="card anim-up">'+[["Name",l.owner_name],["Phone",l.owner_phone],["Email",l.owner_email],["Mailing",l.mailing_address],["Absentee",l.is_absentee?"Yes":"No"],["Out of State",l.is_out_of_state?"Yes":"No"],["Institutional",l.is_institutional?"Yes":"No"],["Years Owned",l.years_owned],["Equity",l.equity_percent?l.equity_percent+"%":"\u2014"]].map(([k,v])=>'<div class="d-row"><span class="d-label">'+k+'</span><span class="d-val">'+(v||"\u2014")+'</span></div>').join("")+'</div>';}else if(tab==="history"){dc.innerHTML='<div class="card anim-up"><div class="card-header"><h3><i class="fas fa-database" style="color:var(--purple)"></i> Enrichment Log</h3></div><div class="table-inner"><table><thead><tr><th>Source</th><th>Status</th><th>Fields</th><th>Duration</th><th>Date</th></tr></thead><tbody>'+(l.enrichment_logs||[]).map(g=>'<tr><td style="font-family:var(--mono);font-size:11px">'+g.source+'</td><td style="color:'+(g.status==="success"?"var(--emerald)":"var(--red)")+'">'+g.status+'</td><td style="font-size:11px">'+(g.fields||[]).join(", ")||"\u2014"+'</td><td style="font-family:var(--mono);font-size:11px">'+(g.duration?g.duration.toFixed(1)+"s":"\u2014")+'</td><td style="font-size:11px">'+fdate(g.at)+'</td></tr>').join("")||'<tr><td colspan="5" style="text-align:center;padding:20px;color:var(--text-500)">No logs</td></tr>'+'</tbody></table></div></div>';}else if(tab==="comps"){dc.innerHTML='<div class="card anim-up"><div class="card-header"><h3><i class="fas fa-balance-scale"></i> Comps</h3></div><div id="compsBox" style="text-align:center;padding:20px"><div class="spinner" style="margin:0 auto"></div></div></div>';API.get("/leads/"+l.id+"/comps/").then(comps=>{const cb=$("#compsBox");if(!cb)return;if(!comps.length){cb.innerHTML='<div style="color:var(--text-500)">No comps found</div>';return;}cb.innerHTML='<div class="table-inner"><table><thead><tr><th>Address</th><th>Beds</th><th>SqFt</th><th>Year</th><th>Last Sale</th><th>Price</th><th>Score</th></tr></thead><tbody>'+comps.map(c=>'<tr style="cursor:pointer" onclick="nav(\'lead\',{id:'+c.id+'})"><td>'+c.address+'</td><td>'+c.beds+'</td><td>'+(c.sqft||"\u2014")+'</td><td>'+(c.year_built||"\u2014")+'</td><td>'+fdate(c.last_sale_date)+'</td><td>'+money(c.last_sale_price)+'</td><td><span class="score '+sc(c.distress_score)+'">'+c.distress_score+'</span></td></tr>').join("")+'</tbody></table></div>';}).catch(()=>{const cb=$("#compsBox");if(cb)cb.innerHTML='<div style="color:var(--text-500)">Failed</div>';});}}});

/* Map */
reg("map",async()=>{shell("map",loading());try{const[md,cfg]=await Promise.all([API.get("/leads/map_data/?"+fq()),S.config.google_maps_key?Promise.resolve(S.config):API.get("/leads/config/")]);S.mapData=md;S.config=cfg;}catch(e){}const mc=$("#mc");if(!mc)return;mc.innerHTML='<div class="page-head anim-down"><div><h1>Map Intelligence</h1><div class="sub">'+S.mapData.length+' properties</div></div></div><div class="map-full"><div id="mapBox" style="display:flex;align-items:center;justify-content:center"><div style="text-align:center;color:var(--text-400)"><i class="fas fa-map-marked-alt" style="font-size:48px;color:var(--blue);margin-bottom:16px;display:block"></i>'+(S.config.google_maps_key?"<p>Loading...</p>":"<p>Set GOOGLE_MAPS_API_KEY</p>")+'</div></div><div class="map-legend"><div style="font-weight:700;font-size:11px;margin-bottom:8px">Score</div><div class="legend-item"><div class="legend-dot hot"></div>Critical (80+)</div><div class="legend-item"><div class="legend-dot warm"></div>High (50-79)</div><div class="legend-item"><div class="legend-dot cold"></div>Standard</div></div></div>';if(S.config.google_maps_key)loadGMap();});
function loadGMap(){if(window.google?.maps){initGMap();return;}const s=document.createElement("script");s.src="https://maps.googleapis.com/maps/api/js?key="+S.config.google_maps_key+"&callback=__gm";s.async=true;window.__gm=initGMap;document.head.appendChild(s);}
function initGMap(){const c=document.getElementById("mapBox");if(!c||!window.google)return;c.innerHTML="";const map=new google.maps.Map(c,{center:{lat:37.5,lng:-122.1},zoom:10,styles:[{elementType:"geometry",stylers:[{color:"#f1f5f9"}]},{elementType:"labels.text.fill",stylers:[{color:"#64748b"}]},{featureType:"water",elementType:"geometry",stylers:[{color:"#dbeafe"}]},{featureType:"road",elementType:"geometry",stylers:[{color:"#ffffff"}]}]});S.mapInstance=map;const iw=new google.maps.InfoWindow();S.mapInfoWindow=iw;const bounds=new google.maps.LatLngBounds();const markers=[];S.mapData.forEach(p=>{const color=p.score>=80?"#ef4444":p.score>=50?"#f59e0b":"#64748b";const pos={lat:p.lat,lng:p.lng};bounds.extend(pos);const m=new google.maps.Marker({position:pos,icon:{path:google.maps.SymbolPath.CIRCLE,scale:6,fillColor:color,fillOpacity:.8,strokeWeight:1.5,strokeColor:"rgba(255,255,255,0.5)"}});m.addListener("click",function(){iw.setContent('<div style="background:white;color:#1e293b;padding:12px;border-radius:8px;min-width:200px;font-family:Inter"><div style="font-size:22px;font-weight:800;color:'+color+'">'+p.score+'</div><div style="font-weight:600">'+p.address+'</div><div style="font-size:11px;color:#64748b">'+p.county+' \u2022 '+money(p.price)+'</div><a href="#" onclick="nav(\'lead\',{id:'+p.id+'});return false" style="color:#0049B8;font-size:12px;margin-top:6px;display:block">View \u2192</a></div>');iw.open(map,m);});markers.push(m);});S.mapMarkers=markers;if(markers.length>0){map.fitBounds(bounds);}if(window.markerClusterer){S.mapClusterer=new markerClusterer.MarkerClusterer({map:map,markers:markers});}else{markers.forEach(function(m){m.setMap(map)});}}

/* Export */
reg("export",async()=>{shell("export",loading());try{S.exportPreview=await API.get("/leads/export_preview/?"+fq());}catch(e){}const mc=$("#mc"),ep=S.exportPreview;if(!mc||!ep)return;mc.innerHTML='<div class="page-head anim-down"><div><h1>Export Center</h1><div class="sub">Download filtered leads as CSV</div></div></div><div class="export-summary anim-up d1"><div class="es-item"><div class="es-val">'+ep.total.toLocaleString()+'</div><div class="es-lbl">Matching</div></div><div class="es-item"><div class="es-val">'+Math.min(ep.total,5000).toLocaleString()+'</div><div class="es-lbl">Export Limit</div></div></div><div class="card anim-up d2" style="margin-bottom:24px"><button class="btn btn-primary" onclick="window.__downloadCSV()" style="width:100%"><i class="fas fa-download"></i> Download CSV ('+Math.min(ep.total,5000).toLocaleString()+' rows)</button></div><div class="card anim-up d3"><div class="card-header"><h3><i class="fas fa-eye" style="color:var(--blue-bright)"></i> Preview</h3></div><div class="table-inner" style="max-height:350px;overflow-y:auto"><table><thead><tr><th>Score</th><th>Address</th><th>County</th><th>Owner</th><th>Value</th></tr></thead><tbody>'+(ep.preview||[]).map(r=>'<tr><td><span class="score '+sc(r.score)+'">'+r.score+'</span></td><td>'+r.address+'</td><td>'+r.county+'</td><td>'+(r.owner||"\u2014")+'</td><td style="font-family:var(--mono)">'+money(r.est_value||r.assessed)+'</td></tr>').join("")+'</tbody></table></div></div>';});
window.__downloadCSV=()=>{var q=fq();var sep=q?"&":"";window.open(API.base+"/leads/export_csv/?"+q+sep+"token="+encodeURIComponent(S.token),"_blank");};

/* Import CSV */
reg("import",async()=>{
shell("import",loading());
try{S.importBatches=await API.get("/import/batches/");}catch(e){S.importBatches=[];}
const mc=$("#mc");if(!mc)return;
mc.innerHTML='<div class="page-head anim-down"><div><h1>Import CSV</h1><div class="sub">Upload property data with human review before import</div></div></div>'+
'<div class="card anim-up d1" style="margin-bottom:24px"><div class="upload-zone" id="uploadZone"><i class="fas fa-cloud-upload-alt"></i><div class="uz-title">Drop CSV file here or click to browse</div><div class="uz-sub">Supports APN, Address, Owner, Property details, Financials and more</div><input type="file" accept=".csv" id="csvFile"></div><div style="margin-top:14px;display:flex;align-items:center;gap:14px"><label class="as-toggle"><input type="checkbox" id="autoImport"> <label style="font-size:12px;color:var(--text-300)">Auto-import if all rows valid (skip review)</label></label></div></div>'+
'<div id="uploadResult" style="display:none" class="card anim-up d2" style="margin-bottom:24px"></div>'+
'<div class="card anim-up d3"><div class="card-header"><h3><i class="fas fa-history" style="color:var(--purple)"></i> Import History</h3></div><div id="batchList">'+
(S.importBatches.length?S.importBatches.map(b=>'<div class="batch-card" onclick="window.__viewBatch(\''+b.id+'\')"><div style="display:flex;align-items:center;justify-content:space-between"><div><span style="font-weight:700">'+b.filename+'</span><span class="row-status rs-'+b.status+'" style="margin-left:8px">'+b.status+'</span></div><div style="font-size:11px;color:var(--text-500)">'+fdate(b.created_at)+'</div></div><div style="font-size:12px;color:var(--text-400);margin-top:6px">'+b.total_rows+' rows \u2022 '+b.valid_rows+' valid \u2022 '+b.error_rows+' errors \u2022 '+b.duplicate_rows+' dupes \u2022 '+b.imported_rows+' imported</div></div>').join(""):'<div style="text-align:center;padding:24px;color:var(--text-500)">No imports yet</div>')+
'</div></div>';
const zone=$("#uploadZone"),fileInput=$("#csvFile");
zone.onclick=()=>fileInput.click();
zone.ondragover=e=>{e.preventDefault();zone.classList.add("dragover");};
zone.ondragleave=()=>zone.classList.remove("dragover");
zone.ondrop=e=>{e.preventDefault();zone.classList.remove("dragover");if(e.dataTransfer.files.length)doUpload(e.dataTransfer.files[0]);};
fileInput.onchange=()=>{if(fileInput.files.length)doUpload(fileInput.files[0]);};
});

async function doUpload(file){
const res=$("#uploadResult");if(!res)return;
res.style.display="block";res.innerHTML='<div style="display:flex;align-items:center;gap:12px"><div class="spinner"></div><span>Uploading '+file.name+'...</span></div>';
try{
const fd=new FormData();fd.append("file",file);fd.append("auto_import",$("#autoImport")?.checked?"true":"false");
const r=await API.upload("/import/upload/",fd);
if(r.auto_imported){
res.innerHTML='<div style="padding:16px;background:rgba(16,185,129,0.06);border:1px solid rgba(16,185,129,0.15);border-radius:var(--r-sm)"><div style="font-weight:700;font-size:16px;color:var(--emerald);margin-bottom:8px"><i class="fas fa-check-circle"></i> Auto-Imported!</div><div style="font-size:13px;color:var(--text-300)">'+r.imported+' rows imported, '+r.duplicates+' duplicates skipped</div></div>';
toast("Imported "+r.imported+" records","ok");
}else{
res.innerHTML='<div style="padding:16px;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);border-radius:var(--r-sm)"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px"><div style="font-weight:700;font-size:16px;color:var(--blue-bright)"><i class="fas fa-clipboard-check"></i> Ready for Review</div><div style="font-size:12px;color:var(--text-500)">'+r.filename+'</div></div><div class="review-stats"><div class="review-stat"><div class="rv">'+r.total_rows+'</div><div class="rl">Total</div></div><div class="review-stat"><div class="rv" style="color:var(--emerald)">'+r.valid_rows+'</div><div class="rl">Valid</div></div><div class="review-stat"><div class="rv" style="color:var(--red)">'+r.error_rows+'</div><div class="rl">Errors</div></div><div class="review-stat"><div class="rv" style="color:var(--amber)">'+r.duplicate_rows+'</div><div class="rl">Dupes</div></div></div>'+(r.unmapped_columns.length?'<div style="margin-top:14px;font-size:11px;color:var(--text-500)"><strong>Unmapped columns:</strong> '+r.unmapped_columns.join(", ")+'</div>':'')+'<div style="margin-top:18px"><div class="table-inner" style="max-height:260px;overflow-y:auto"><table><thead><tr><th>Row</th><th>Status</th><th>APN</th><th>County</th><th>Address</th><th>Owner</th><th>Errors</th></tr></thead><tbody>'+(r.preview||[]).map(row=>'<tr><td>'+row.row+'</td><td><span class="row-status rs-'+row.status+'">'+row.status+'</span></td><td style="font-family:var(--mono);font-size:11px">'+row.apn+'</td><td>'+row.county+'</td><td>'+row.address+'</td><td>'+row.owner+'</td><td style="font-size:11px;color:var(--red)">'+(row.errors||[]).join("; ")+'</td></tr>').join("")+'</tbody></table></div></div><div style="display:flex;gap:10px;margin-top:18px"><button class="btn btn-primary btn-sm" onclick="window.__approveBatch(\''+r.batch_id+'\')"><i class="fas fa-check"></i> Approve & Import ('+r.valid_rows+' valid rows)</button><button class="btn btn-danger btn-sm" onclick="window.__rejectBatch(\''+r.batch_id+'\')"><i class="fas fa-times"></i> Reject All</button><button class="btn btn-secondary btn-sm" onclick="window.__viewBatch(\''+r.batch_id+'\')"><i class="fas fa-eye"></i> Full Review</button></div></div>';
}
}catch(e){res.innerHTML='<div style="padding:16px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:var(--r-sm);color:var(--red)"><i class="fas fa-exclamation-circle"></i> '+e.message+'</div>';}
}

window.__approveBatch=async id=>{try{const r=await API.post("/import/batch/"+id+"/approve/");toast("Imported "+r.imported+" records!","ok");nav("import");}catch(e){toast(e.message,"err");}};
window.__rejectBatch=async id=>{if(!confirm("Reject this entire batch?"))return;try{await API.post("/import/batch/"+id+"/reject/");toast("Batch rejected","info");nav("import");}catch(e){toast(e.message,"err");}};
window.__viewBatch=async id=>{
try{const b=await API.get("/import/batch/"+id+"/");
const ov=document.createElement("div");ov.className="modal-overlay";ov.onclick=e=>{if(e.target===ov)ov.remove();};
ov.innerHTML='<div class="modal" style="max-width:800px"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px"><h2>'+b.filename+'</h2><span class="row-status rs-'+b.status+'" style="font-size:12px;padding:4px 14px">'+b.status+'</span></div><div class="review-stats" style="margin-bottom:20px"><div class="review-stat"><div class="rv">'+b.total_rows+'</div><div class="rl">Total</div></div><div class="review-stat"><div class="rv" style="color:var(--emerald)">'+b.valid_rows+'</div><div class="rl">Valid</div></div><div class="review-stat"><div class="rv" style="color:var(--red)">'+b.error_rows+'</div><div class="rl">Errors</div></div><div class="review-stat"><div class="rv" style="color:var(--amber)">'+b.duplicate_rows+'</div><div class="rl">Dupes</div></div><div class="review-stat"><div class="rv" style="color:var(--blue)">'+b.imported_rows+'</div><div class="rl">Imported</div></div></div><div class="table-inner" style="max-height:400px;overflow-y:auto"><table><thead><tr><th>Row</th><th>Status</th><th>APN</th><th>County</th><th>Address</th><th>City</th><th>Owner</th><th>Beds</th><th>Assessed</th><th>Errors</th></tr></thead><tbody>'+(b.rows||[]).map(r=>'<tr><td>'+r.row+'</td><td><span class="row-status rs-'+r.status+'">'+r.status+'</span></td><td style="font-family:var(--mono);font-size:10px">'+r.apn+'</td><td>'+r.county+'</td><td style="max-width:150px;overflow:hidden;text-overflow:ellipsis">'+r.address+'</td><td>'+r.city+'</td><td>'+r.owner+'</td><td>'+r.beds+'</td><td style="font-family:var(--mono)">'+money(r.assessed)+'</td><td style="font-size:11px;color:var(--red)">'+(r.errors||[]).join("; ")+'</td></tr>').join("")+'</tbody></table></div><div class="modal-actions">'+(b.status==="pending"?'<button class="btn btn-primary btn-sm" onclick="window.__approveBatch(\''+id+'\');this.closest(\'.modal-overlay\').remove()"><i class="fas fa-check"></i> Approve</button><button class="btn btn-danger btn-sm" onclick="window.__rejectBatch(\''+id+'\');this.closest(\'.modal-overlay\').remove()"><i class="fas fa-times"></i> Reject</button>':'')+'<button class="btn btn-ghost btn-sm" onclick="this.closest(\'.modal-overlay\').remove()">Close</button></div></div>';
document.body.appendChild(ov);
}catch(e){toast("Failed to load batch","err");}
};

/* Scrapers + Active Op Detail */
reg("scrapers",async()=>{
if(!S.user?.is_admin_role&&S.user?.role!=="admin"){toast("Admin required","err");nav("dashboard");return;}
shell("scrapers",loading());
try{const[ov,ops,hist,act]=await Promise.all([API.get("/scrapers/overview/"),API.get("/enrichment/operations/"),API.get("/enrichment/history/?limit=25"),API.get("/enrichment/active/")]);S.scrapers=ov.scrapers||[];S.scraperSum=ov.summary||{};S.operations=ops;S.opHistory=hist;S.activeOps=act;}catch(e){toast("Load failed","err");}
const sm=S.scraperSum,mc=$("#mc"),ac=S.activeOps.length;if(!mc)return;
mc.innerHTML='<div class="page-head anim-down"><div><h1>Trigger Center</h1><div class="sub">'+(sm.total||0)+' data sources \u2022 '+(sm.total_records||0).toLocaleString()+' records collected</div></div></div><div class="stats-row"><div class="stat emerald anim-up d1"><div class="stat-icon ic-emerald"><i class="fas fa-check-circle"></i></div><div class="stat-val">'+(sm.healthy||0)+'</div><div class="stat-label">Healthy</div></div><div class="stat warm anim-up d2"><div class="stat-icon ic-amber"><i class="fas fa-exclamation-triangle"></i></div><div class="stat-val">'+(sm.degraded||0)+'</div><div class="stat-label">Degraded</div></div><div class="stat hot anim-up d3"><div class="stat-icon ic-red"><i class="fas fa-times-circle"></i></div><div class="stat-val">'+(sm.down||0)+'</div><div class="stat-label">Down</div></div><div class="stat '+(ac?"blue":"")+' anim-up d4"><div class="stat-icon ic-blue"><i class="fas fa-satellite-dish"></i></div><div class="stat-val">'+ac+'</div><div class="stat-label">Active</div></div></div><div class="tabs" id="stabs"><button class="tab-btn '+(S.scraperTab==="operations"?"active":"")+'" data-t="operations">Actions</button><button class="tab-btn '+(S.scraperTab==="active"?"active":"")+'" data-t="active"><span class="live-dot" style="'+(ac?"":"display:none")+'"></span>Live'+(ac?" ("+ac+")":"")+'</button><button class="tab-btn '+(S.scraperTab==="history"?"active":"")+'" data-t="history">History</button><button class="tab-btn '+(S.scraperTab==="sources"?"active":"")+'" data-t="sources">Sources</button></div><div id="scraperContent"></div>';
$$("#stabs .tab-btn").forEach(b=>{b.onclick=()=>{S.scraperTab=b.dataset.t;$$("#stabs .tab-btn").forEach(x=>x.classList.remove("active"));b.classList.add("active");renderSTab();}});renderSTab();
if(ac>0)S.activeOpsTimer=setInterval(refreshActiveTab,8000);
});

function renderSTab(){const c=$("#scraperContent");if(!c)return;if(S.scraperTab==="operations")renderOpsTab(c);else if(S.scraperTab==="active")renderActiveTab(c);else if(S.scraperTab==="history")renderHistoryTab(c);else if(S.scraperTab==="sources")renderSourcesTab(c);}

function renderOpsTab(c){const cats={ingest:"\ud83d\udce1 Scrape County Records",enrich:"\u2728 Analyze & Score",owner:"\ud83d\udd0d Owner Intelligence",maintain:"\ud83d\udee0 Cleanup & Export"};const runAll=S.operations["run_all"];let h='';if(runAll){h+='<div class="run-all-hero anim-up d1" onclick="window.__confirmAndRun(\'run_all\')"><div class="run-all-inner"><div class="run-all-icon"><i class="fas fa-rocket"></i></div><div class="run-all-text"><div class="run-all-title">'+runAll.label+'</div><div class="run-all-desc">'+runAll.description+'</div></div><div class="run-all-btn"><i class="fas fa-play"></i> Run Now</div></div></div>';}h+='<p style="color:var(--text-400);font-size:13px;margin:24px 0">Or run individual actions below. Results appear in the Live tab.</p>';for(const[ck,cl]of Object.entries(cats)){const ops=Object.entries(S.operations).filter(([k,o])=>o.category===ck&&k!=="run_all");if(!ops.length)continue;h+='<h3 style="font-size:14px;font-weight:700;margin:24px 0 14px;color:var(--text-300)">'+cl+'</h3><div class="ops-grid">';h+=ops.map(([key,op],i)=>{var tierLabel=op.tier===1?"Fast":op.tier===2?"Medium":"Slow";return'<div class="op-card op-'+op.color+' anim-up d'+(Math.min(i+1,6))+'" onclick="window.__confirmAndRun(\''+key+'\')"><div class="op-head"><div class="op-icon ic-'+op.color+'"><i class="fas '+op.icon+'"></i></div><div class="op-name">'+op.label+'</div></div><div class="op-desc">'+op.description+'</div><div class="op-meta"><span><i class="fas fa-tachometer-alt"></i> '+tierLabel+'</span><span><i class="fas fa-clock"></i> ~'+op.estimated_time+'</span></div></div>';}).join("")+"</div>";}c.innerHTML=h;}

function renderActiveTab(c){
if(!S.activeOps.length){c.innerHTML='<div class="card" style="text-align:center;padding:48px;color:var(--text-500)"><i class="fas fa-satellite-dish" style="font-size:36px;margin-bottom:14px;display:block;color:var(--text-600)"></i><div style="font-size:17px;font-weight:700;margin-bottom:6px">Nothing Running</div><div style="font-size:13px">Launch an action from the Actions tab</div></div>';return;}
c.innerHTML='<div style="font-size:13px;color:var(--text-400);margin-bottom:18px"><span class="live-dot"></span>Live updates \u2022 Click for details</div>'+S.activeOps.map(op=>{
const pct=Math.min(95,(op.step_count||0)*7);
return'<div class="card" style="margin-bottom:14px;border-left:3px solid var(--blue);cursor:pointer" id="active-op-'+op.id+'" onclick="window.__activeDetail('+op.id+')"><div style="display:flex;align-items:center;gap:14px;margin-bottom:10px"><div class="spinner" style="width:20px;height:20px;border-width:2px;flex-shrink:0"></div><div style="flex:1"><div style="font-weight:700;font-size:16px">'+op.label+'</div><div style="font-size:11px;color:var(--text-500)" class="op-live-step">'+(op.steps?.length?(op.steps[op.steps.length-1].detail||op.steps[op.steps.length-1].name):"Running...")+'</div></div><button class="btn btn-danger btn-sm" onclick="event.stopPropagation();window.__stop('+op.id+')"><i class="fas fa-stop"></i> Stop</button></div><div class="progress-bar"><div class="progress-fill" style="width:'+pct+'%"></div></div><div style="display:flex;gap:14px;font-family:var(--mono);font-size:12px;margin-top:6px"><span class="op-cr" style="color:var(--emerald)">'+(op.leads_created?"+"+op.leads_created+" new":"")+'</span><span class="op-up" style="color:var(--blue)">'+(op.leads_updated?op.leads_updated+" upd":"")+'</span><span class="op-en" style="color:var(--cyan)">'+(op.leads_enriched?op.leads_enriched+" enr":"")+'</span><span class="op-fa" style="color:var(--red)">'+(op.leads_failed?op.leads_failed+" fail":"")+'</span><span class="op-steps" style="color:var(--text-500)">'+op.step_count+' steps</span><span style="color:var(--text-500)">'+(op.elapsed?Math.round(op.elapsed)+"s":"")+'</span></div></div>';}).join("");}

window.__activeDetail=async id=>{
let op;try{op=await API.get("/enrichment/history/"+id+"/");}catch(e){
const ao=S.activeOps.find(x=>x.id===id);if(!ao){toast("Not found","err");return;}op=ao;}
const ov=document.createElement("div");ov.className="modal-overlay";ov.onclick=e=>{if(e.target===ov)ov.remove();};
const isActive=op.is_active||op.status==="running";
ov.innerHTML='<div class="modal" style="max-width:640px"><div class="op-detail-live"><div style="display:flex;align-items:center;gap:12px;margin-bottom:4px">'+(isActive?'<div class="spinner" style="width:20px;height:20px;border-width:2px"></div>':'<i class="fas '+stIcon(op.status)+'" style="color:'+stColor(op.status)+';font-size:20px"></i>')+'<h2 style="margin:0;font-size:18px">'+op.label+'</h2></div><div style="font-size:12px;color:var(--text-500);margin-bottom:16px">'+(op.triggered_by||"system")+' \u2022 '+ftime(op.started_at)+(op.duration_seconds?' \u2022 '+op.duration_seconds+'s':'')+'</div><div class="op-counters"><div class="op-counter"><div class="oc-v" style="color:var(--emerald)">'+(op.leads_created||0)+'</div><div class="oc-l">Created</div></div><div class="op-counter"><div class="oc-v" style="color:var(--blue)">'+(op.leads_updated||0)+'</div><div class="oc-l">Updated</div></div><div class="op-counter"><div class="oc-v" style="color:var(--cyan)">'+(op.leads_enriched||0)+'</div><div class="oc-l">Enriched</div></div><div class="op-counter"><div class="oc-v" style="color:var(--red)">'+(op.leads_failed||0)+'</div><div class="oc-l">Failed</div></div></div>'+(isActive?'<div class="op-progress-section"><div style="font-size:11px;color:var(--text-500);margin-bottom:4px">Progress</div><div class="progress-bar" style="height:6px"><div class="progress-fill" style="width:'+Math.min(95,(op.steps||[]).length*7)+'%"></div></div></div>':'')+'<div style="font-size:12px;font-weight:700;margin:14px 0 8px;color:var(--text-300)">Steps ('+(op.steps||[]).length+')</div><div class="op-steps-live">'+(op.steps||[]).map(s=>'<div class="op-step-item"><div class="op-step-icon"><i class="fas '+(s.status==="success"?"fa-check-circle":s.status==="error"?"fa-times-circle":"fa-exclamation-circle")+'" style="color:'+(s.status==="success"?"var(--emerald)":s.status==="error"?"var(--red)":"var(--amber)")+'"></i></div><div class="op-step-body"><div class="op-step-name">'+s.name+'</div>'+(s.detail?'<div class="op-step-detail">'+s.detail+'</div>':'')+(s.error?'<div class="op-step-error">'+s.error+'</div>':'')+'</div>'+(s.records?'<span style="font-family:var(--mono);font-size:10px;color:var(--text-500)">'+s.records+' rec</span>':'')+'</div>').join("")||'<div style="color:var(--text-500);text-align:center;padding:12px">No steps yet</div>'+'</div></div><div class="modal-actions">'+(isActive?'<button class="btn btn-danger btn-sm" onclick="window.__stop('+op.id+');this.closest(\'.modal-overlay\').remove()"><i class="fas fa-stop"></i> Stop</button>':'')+'<button class="btn btn-secondary btn-sm" onclick="this.closest(\'.modal-overlay\').remove()">Close</button></div></div>';
document.body.appendChild(ov);
};

window.__stop=async id=>{if(!confirm("Stop this operation?"))return;try{await API.post("/enrichment/cancel/"+id+"/");toast("Stopping...","info");setTimeout(refreshActiveTab,1000);}catch(e){toast(e.message,"err");}};

function renderHistoryTab(c){if(!S.opHistory?.length){c.innerHTML='<div class="card" style="text-align:center;padding:36px;color:var(--text-500)">No operations yet</div>';return;}c.innerHTML=S.opHistory.map(op=>'<div class="card" style="margin-bottom:10px;cursor:pointer" onclick="window.__activeDetail('+op.id+')"><div style="display:flex;align-items:center;justify-content:space-between"><div style="display:flex;align-items:center;gap:12px"><i class="fas '+stIcon(op.status)+'" style="color:'+stColor(op.status)+';font-size:16px"></i><div><div style="font-weight:700;font-size:13.5px">'+op.label+'</div><div style="font-size:10px;color:var(--text-500)">'+ftime(op.started_at)+' \u2022 '+(op.triggered_by||"system")+' \u2022 '+op.duration_seconds+'s</div></div></div><div style="display:flex;gap:10px;font-size:11px;font-family:var(--mono)">'+(op.leads_created?'<span style="color:var(--emerald)">+'+op.leads_created+'</span>':'')+(op.leads_updated?'<span style="color:var(--blue)">'+op.leads_updated+'</span>':'')+(op.leads_failed?'<span style="color:var(--red)">'+op.leads_failed+' fail</span>':'')+'</div></div></div>').join("");}

function renderSourcesTab(c){c.innerHTML='<div class="scrapers-list">'+S.scrapers.map(s=>'<div class="sc-card"><div class="sc-top"><div class="sc-name"><span class="health-dot h-'+s.health+'"></span>'+s.name+'</div><span class="tier-badge t'+s.tier+'">T'+s.tier+'</span></div><div class="sc-meta">'+(s.type||"").toUpperCase()+' \u2022 '+(s.county||"All")+' \u2022 '+s.category+'</div><div class="sc-metrics"><div class="sc-m"><div class="v" style="color:var(--emerald)">'+s.successes+'</div><div class="l">OK</div></div><div class="sc-m"><div class="v" style="color:var(--red)">'+s.failures+'</div><div class="l">Fail</div></div><div class="sc-m"><div class="v">'+s.records_fetched.toLocaleString()+'</div><div class="l">Records</div></div></div><button class="btn btn-secondary btn-xs" onclick="window.__toggleSc('+s.id+')"><i class="fas fa-'+(s.active?"pause":"play")+'"></i> '+(s.active?"Disable":"Enable")+'</button></div>').join("")+'</div>';}
window.__toggleSc=async id=>{try{const r=await API.post("/scrapers/"+id+"/toggle/");toast("Source "+(r.active?"enabled":"disabled"),"ok");nav("scrapers");}catch(e){toast(e.message,"err");}};

window.__opModal=key=>{const op=S.operations[key];if(!op)return;const ov=document.createElement("div");ov.className="modal-overlay";ov.onclick=e=>{if(e.target===ov)ov.remove()};let ph="";if(op.requires.indexOf("county")>=0)ph+='<div class="form-group"><label class="form-label">County</label><select class="form-input" id="opCo">'+["Santa Clara","San Mateo","Alameda","San Francisco","Contra Costa","Marin","Sonoma","Napa","Solano"].map(c=>"<option>"+c+"</option>").join("")+"</select></div>";if(op.requires.indexOf("days")>=0)ph+='<div class="form-group"><label class="form-label">Days</label><input type="number" class="form-input" id="opD" value="7" min="1" max="90"></div>';ov.innerHTML='<div class="modal"><h2><i class="fas '+op.icon+'" style="color:var(--'+op.color+');margin-right:10px"></i>'+op.label+'</h2><div class="desc">'+op.description+'</div>'+ph+'<div id="opR" style="display:none"></div><div class="modal-actions"><button class="btn btn-ghost btn-sm" onclick="this.closest(\'.modal-overlay\').remove()">Cancel</button><button class="btn btn-primary btn-sm" id="opGo"><i class="fas fa-play"></i> Execute</button></div></div>';document.body.appendChild(ov);
ov.querySelector("#opGo").onclick=async()=>{const p={};const ce=ov.querySelector("#opCo");if(ce)p.county=ce.value;const de=ov.querySelector("#opD");if(de)p.days=de.value;const btn=ov.querySelector("#opGo"),re=ov.querySelector("#opR");btn.innerHTML='<div class="spinner" style="width:14px;height:14px;border-width:2px"></div> Starting...';btn.disabled=true;try{const res=await API.post("/enrichment/run/",{operation:key,params:p});if(res.is_active){toast(res.label+" started","ok");ov.remove();S.scraperTab="active";nav("scrapers");}else{re.style.display="block";const bgc=res.status==="completed"?"16,185,129":"239,68,68";var sheetLink=res.sheet_url?'<div style="margin-top:12px"><a href="'+res.sheet_url+'" target="_blank" rel="noopener" style="display:inline-flex;align-items:center;gap:8px;padding:10px 18px;background:rgba(16,185,129,0.08);border:1px solid rgba(16,185,129,0.2);border-radius:var(--r-sm);color:var(--emerald);font-weight:600;font-size:13px;text-decoration:none;transition:all .2s"><i class="fas fa-external-link-alt"></i> Open Google Sheet</a></div>':"";re.innerHTML='<div style="padding:18px;background:rgba('+bgc+',0.06);border:1px solid rgba('+bgc+',0.15);border-radius:var(--r-sm);margin-top:18px"><div style="font-weight:700;color:'+stColor(res.status)+'">'+res.status.toUpperCase()+' \u2022 '+res.duration_seconds+'s</div><div style="margin-top:10px;font-size:12px;color:var(--text-300)">Created: '+res.leads_created+' | Updated: '+res.leads_updated+' | Enriched: '+res.leads_enriched+'</div>'+sheetLink+'</div>';btn.innerHTML='Done';toast(res.sheet_url?res.label+": "+res.leads_updated+" rows synced":res.label+": "+res.status,res.status==="completed"?"ok":"err");}}catch(e){re.style.display="block";re.innerHTML='<div style="color:var(--red);margin-top:16px">'+e.message+'</div>';btn.innerHTML='Retry';btn.disabled=false;}};};

/* Init */
window.nav=nav;window.S=S;
const st=localStorage.getItem("token"),sr=localStorage.getItem("refresh"),su=localStorage.getItem("user");
if(st&&su){S.token=st;S.refresh=sr;try{S.user=JSON.parse(su)}catch{S.user=null}if(S.user){connectWS();const lv=localStorage.getItem("lastView");if(lv){try{const v=JSON.parse(lv);nav(v.p||"dashboard",v.params||{});}catch{nav("dashboard");}}else nav("dashboard");}else nav("login");}else nav("login");
})();


/* === Bay Sentinel v10 — Confirmation + Coverage === */
window.__confirmAndRun = function(key) {
    var op = S.operations[key];
    if (!op) { window.__opModal(key); return; }
    var isDanger = op.danger || false;
    var iconType = isDanger ? 'danger' : 'warn';
    var iconCls = isDanger ? 'fa-exclamation-triangle' : 'fa-play-circle';
    var btnCls = isDanger ? 'btn-danger' : 'btn-primary';

    var ov = document.createElement('div');
    ov.className = 'confirm-overlay';
    ov.onclick = function(e) { if (e.target === ov) ov.remove(); };

    var desc = op.description || '';
    if (desc.length > 160) desc = desc.substring(0, 160) + '...';

    ov.innerHTML = '<div class="confirm-box">' +
        '<div class="confirm-icon ' + iconType + '">' +
        '<i class="fas ' + iconCls + '"></i></div>' +
        '<div class="confirm-title">' + (isDanger ? 'Are you sure?' : 'Run this action?') + '</div>' +
        '<div class="confirm-msg"><strong>' + op.label + '</strong><br><br>' + desc + '</div>' +
        '<div style="font-size:11px;color:var(--text-500);margin-bottom:20px">' +
        '<i class="fas fa-clock"></i> Takes about ' + (op.estimated_time || 'a few seconds') + '</div>' +
        '<div class="confirm-actions">' +
        '<button class="btn btn-ghost btn-sm" id="cfCancel">Cancel</button>' +
        '<button class="btn ' + btnCls + ' btn-sm" id="cfGo">' +
        '<i class="fas fa-play"></i> Run Now</button></div></div>';

    document.body.appendChild(ov);
    document.getElementById('cfCancel').onclick = function() { ov.remove(); };
    document.getElementById('cfGo').onclick = function() { ov.remove(); window.__opModal(key); };
};
